/* Bootstrap 5 Minimal JS - Navbar Toggle & Basic Components */
(function(){
  'use strict';
  // Navbar toggler
  document.addEventListener('DOMContentLoaded', function() {
    // Navbar toggle
    document.querySelectorAll('[data-bs-toggle="collapse"]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var target = document.querySelector(btn.getAttribute('data-bs-target') || btn.getAttribute('href'));
        if (target) {
          target.classList.toggle('show');
        }
      });
    });
    // Dismiss alerts
    document.querySelectorAll('[data-bs-dismiss="alert"]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var alert = btn.closest('.alert');
        if (alert) alert.remove();
      });
    });
    // Tab support
    document.querySelectorAll('[data-bs-toggle="tab"]').forEach(function(tab) {
      tab.addEventListener('click', function(e) {
        e.preventDefault();
        var target = document.querySelector(tab.getAttribute('data-bs-target') || tab.getAttribute('href'));
        var parent = tab.closest('[role="tablist"]') || tab.parentElement.parentElement;
        parent.querySelectorAll('[data-bs-toggle="tab"]').forEach(function(t){ t.classList.remove('active'); });
        document.querySelectorAll('.tab-pane').forEach(function(p){ p.classList.remove('show','active'); });
        tab.classList.add('active');
        if(target){ target.classList.add('show','active'); }
      });
    });
    // Modal support
    document.querySelectorAll('[data-bs-toggle="modal"]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var target = document.querySelector(btn.getAttribute('data-bs-target'));
        if(target){
          target.style.display = 'block';
          target.classList.add('show');
          document.body.classList.add('modal-open');
          var backdrop = document.createElement('div');
          backdrop.className = 'modal-backdrop fade show';
          backdrop.id = 'modalBackdrop';
          document.body.appendChild(backdrop);
        }
      });
    });
    document.querySelectorAll('[data-bs-dismiss="modal"]').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var modal = btn.closest('.modal');
        if(modal){ modal.style.display='none'; modal.classList.remove('show'); }
        document.body.classList.remove('modal-open');
        var bd = document.getElementById('modalBackdrop');
        if(bd) bd.remove();
      });
    });
  });
})();
